allow:
Bash(powershell -Command "
@'
@page
@model FishingPortDemo.Pages.IndexModel
@{
    ViewData[\\"Title\\"] = \\"系统首页\\";
    Layout = null;
}
<!DOCTYPE html>
<html lang=\\"zh-CN\\">
<head>
    <meta charset=\\"utf-8\\" />
    <meta name=\\"viewport\\" content=\\"width=device-width, initial-scale=1.0\\" />
    <title>智慧渔港运营系统</title>
    <link rel=\\"stylesheet\\" href=\\"lib/bootstrap/dist/css/bootstrap.min.css\\" />
    <link rel=\\"stylesheet\\" href=\\"https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.0/font/bootstrap-icons.css\\" />
    <style>
        body { background: linear-gradient\(135deg, #0a1628 0%, #1a3a5c 50%, #0d2137 100%\); min-height: 100vh; display: flex; align-items: center; justify-content: center; font-family: 'Microsoft YaHei', sans-serif; }
        .login-card { background: rgba\(255,255,255,0.05\); backdrop-filter: blur\(20px\); border: 1px solid rgba\(255,255,255,0.1\); border-radius: 20px; padding: 50px 40px; width: 420px; box-shadow: 0 25px 60px rgba\(0,0,0,0.5\); }
        .system-title { color: #00d4ff; font-size: 1.8rem; font-weight: 700; text-align: center; margin-bottom: 8px; }
        .system-subtitle { color: rgba\(255,255,255,0.6\); text-align: center; margin-bottom: 35px; font-size: 0.9rem; }
        .form-control { background: rgba\(255,255,255,0.08\); border: 1px solid rgba\(255,255,255,0.15\); color: #fff; border-radius: 10px; padding: 12px 15px; }
        .form-control:focus { background: rgba\(255,255,255,0.12\); border-color: #00d4ff; color: #fff; box-shadow: 0 0 0 3px rgba\(0,212,255,0.15\); }
        .form-control::placeholder { color: rgba\(255,255,255,0.4\); }
        .btn-login { background: linear-gradient\(135deg, #00d4ff, #0066cc\); border: none; border-radius: 10px; padding: 13px; font-size: 1rem; font-weight: 600; width: 100%; color: #fff; transition: all 0.3s; }
        .btn-login:hover { transform: translateY\(-2px\); box-shadow: 0 8px 25px rgba\(0,212,255,0.4\); color: #fff; }
        .demo-hint { color: rgba\(255,255,255,0.4\); font-size: 0.8rem; text-align: center; margin-top: 20px; }
        .particles { position: fixed; top: 0; left: 0; width: 100%; height: 100%; pointer-events: none; overflow: hidden; z-index: 0; }
        .particle { position: absolute; width: 3px; height: 3px; background: rgba\(0,212,255,0.3\); border-radius: 50%; animation: float linear infinite; }
        @@keyframes float { 0% { transform: translateY\(100vh\) rotate\(0deg\); opacity: 0; } 10% { opacity: 1; } 90% { opacity: 1; } 100% { transform: translateY\(-100px\) rotate\(720deg\); opacity: 0; } }
        .login-card { position: relative; z-index: 1; }
        .logo-icon { font-size: 3rem; color: #00d4ff; text-align: center; margin-bottom: 15px; }
        .form-label { color: rgba\(255,255,255,0.8\); font-size: 0.9rem; }
    </style>
</head>
<body>
    <div class=\\"particles\\" id=\\"particles\\"></div>
    <div class=\\"login-card\\">
        <div class=\\"logo-icon\\"><i class=\\"bi bi-water\\"></i></div>
        <div class=\\"system-title\\">智慧渔港运营系统</div>
        <div class=\\"system-subtitle\\">Smart Fishing Harbor Management System</div>
        <div class=\\"mb-3\\">
            <label class=\\"form-label\\">用户名</label>
            <input type=\\"text\\" class=\\"form-control\\" placeholder=\\"请输入用户名\\" value=\\"admin\\" />
        </div>
        <div class=\\"mb-4\\">
            <label class=\\"form-label\\">密码</label>
            <input type=\\"password\\" class=\\"form-control\\" placeholder=\\"请输入密码\\" value=\\"123456\\" />
        </div>
        <button class=\\"btn btn-login\\" onclick=\\"window.location.href='/Dashboard'\\">登 录</button>
        <div class=\\"demo-hint\\">演示账号：admin / 123456（点击直接进入）</div>
    </div>
    <script src=\\"lib/bootstrap/dist/js/bootstrap.bundle.min.js\\"></script>
    <script>
        const particles = document.getElementById\('particles'\);
        for\(let i = 0; i < 30; i++\) {
            const p = document.createElement\('div'\);
            p.className = 'particle';
            p.style.left = Math.random\(\) * 100 + '%';
            p.style.animationDuration = \(Math.random\(\) * 10 + 8\) + 's';
            p.style.animationDelay = \(Math.random\(\) * 10\) + 's';
            p.style.width = p.style.height = \(Math.random\(\) * 4 + 2\) + 'px';
            particles.appendChild\(p\);
        }
    </script>
</body>
</html>
'@ | Set-Content -Path 'Pages\\Index.cshtml' -Encoding UTF8
Write-Host 'Done Index'
")
